/* ===========================================================================
 * Rendering lifecycle
 *
 * Two interrelated startApp/render bugs are pinned here:
 *
 *  (a) LISTENER LEAK — startApp calls subscribe(render) and used to throw away
 *      the returned unsubscribe function, so every re-mount left the previous
 *      mount's hashchange listener on `window`. (happy-dom dedups identical
 *      function references, so this leak is latent rather than multiplicative
 *      in this environment, but the cleanup contract is still asserted via the
 *      addEventListener/removeEventListener spies below.)
 *  (b) RENDER RACE — render() is async; two rapid navigations let a slower
 *      fetch overwrite a fresher one's results. The fix aborts a superseded
 *      render after each await.
 * ========================================================================= */
describe('rendering lifecycle', () => {
  describe('hashchange listener cleanup on re-mount', () => {
    /**
     * Mount the app `n` times into fresh containers, the way `setup()` does.
     * Returns nothing; used to drive repeated startApp() calls with the spies
     * already installed so every subscribe/unsubscribe is captured.
     */
    function mountNTimes(n: number): void {
      for (let i = 0; i < n; i++) {
        document.body.innerHTML = '';
        window.location.hash = '';
        const root = document.createElement('div');
        document.body.append(root);
        startApp(root);
      }
    }

    function hashchangeCalls(
      spy: ReturnType<typeof vi.spyOn>,
    ): Array<{ type: string; callback: EventListenerOrEventListenerObject }> {
      return spy.mock.calls
        .map(([type, callback]) => ({ type: String(type), callback }))
        .filter((c) => c.type === 'hashchange');
    }

    it('subscribes exactly one hashchange listener per mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');

      mountNTimes(3);
      await flush();

      // Each startApp() subscribes render exactly once.
      expect(hashchangeCalls(addSpy)).toHaveLength(3);
    });

    it("unsubscribes the previous mount's hashchange listener on every re-mount", async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');
      const removeSpy = vi.spyOn(window, 'removeEventListener');

      const N = 4;
      mountNTimes(N);
      await flush();

      const adds = hashchangeCalls(addSpy);
      const removes = hashchangeCalls(removeSpy);

      // Robust to test ordering: the 1st mount in *this* test may additionally
      // tear down a listener left over by an earlier test, so we only assert a
      // lower bound. The invariant that matters is that every re-mount removes
      // its predecessor — i.e. at least (N − 1) hashchange removals happened.
      // The leaky implementation performs ZERO removals.
      expect(adds).toHaveLength(N);
      expect(removes.length).toBeGreaterThanOrEqual(N - 1);
      // Every removal targets the same render callback that was subscribed.
      expect(removes.length).toBeGreaterThan(0);
      for (const r of removes) {
        expect(typeof r.callback).toBe('function');
        expect(adds.some((a) => a.callback === r.callback)).toBe(true);
      }
    });
  });

  describe('render race (superseded fetch is discarded)', () => {
    /**
     * Drive a browse render for `path` whose fetch is held open until the
     * caller invokes `release()`. All other browse paths resolve immediately.
     */
    function stubHeldBrowse(heldPath: string): { release: () => void } {
      let release!: () => void;
      const held = new Promise<Response>((resolve) => {
        release = () =>
          resolve(
            mockResponse({
              body: browseResult({
                path: heldPath,
                entries: [
                  fileEntry({
                    name: 'child-of-' + heldPath,
                    path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                  }),
                ],
                fileCount: 1,
                totalSize: 1,
              }),
            }),
          );
      });

      fetchMock.mockImplementation(async (url, init) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'GET' && u.includes('/browse')) {
          const path = decodeURIComponent(u.split('path=')[1] ?? '');
          if (path === heldPath) {
            return held;
          }
          return mockResponse({
            body: browseResult({
              path,
              entries: [
                fileEntry({
                  name: 'child-of-' + path,
                  path: joinPathHelper(path, 'child-of-' + path),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      });

      return { release };
    }

    it('does not let a slower, superseded browse overwrite the latest results', async () => {
      const { release } = stubHeldBrowse('slow');

      const { results } = setup();
      await flush(); // settle the initial render for the default route

      // Navigate to 'slow' (its fetch is held), then — before it resolves — to
      // 'fast'. In happy-dom each hash assignment fires `hashchange` and thus
      // render() synchronously, so both fetches are issued in order and the
      // 'slow' render is suspended at its await when 'fast' starts.
      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush(); // 'fast' resolves first and commits

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');

      // The slow fetch finally resolves LAST. Its stale data must be discarded
      // (a newer render owns the slot) and must NOT clobber the fresh results.
      release();
      await flush();

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');
    });

    it('does not let a superseded browse update the breadcrumb or status', async () => {
      const { release } = stubHeldBrowse('slow');

      const { breadcrumb, status } = setup();
      await flush();

      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush();

      // The fresh render owns the breadcrumb / status for 'fast'.
      expect(breadcrumb.textContent).toContain('fast');
      expect(status.textContent).toContain('1 files');

      release();
      await flush();

      // The superseded 'slow' render must not have touched them.
      expect(breadcrumb.textContent).toContain('fast');
      expect(breadcrumb.textContent).not.toContain('slow');
      expect(status.textContent).toContain('1 files');
    });

    it('still renders the latest navigation when fetches resolve in order', async () => {
      // Control case: a single navigation (no race) still commits normally,
      // so the race guard does not swallow a non-superseded render.
      const { results } = setup({ hash: toBrowseHash('solo') });
      await flush();

      expect(results.textContent).toContain('child-of-solo');

      navigate(toBrowseHash('next'));
      await flush();

      expect(results.textContent).toContain('child-of-next');
      expect(results.textContent).not.toContain('child-of-solo');
    });
  });
});

/* ===========================================================================
 * Search loading spinner
 *
 * `render()` shows a spinner (a `.search-spinner` div wrapping a
 * `.bi-arrow-repeat.spinning` icon) in the results container while a SEARCH
 * fetch is in flight, and never for a browse route. It is removed once the
 * search table renders (renderSearch clears `innerHTML` first) or, on failure,
 * once the error handler sets `textContent`. The existing race-token guard
 * also keeps a superseded search render from re-adding a stale spinner.
 * ========================================================================= */
describe('search loading spinner', () => {
  /**
   * Drive a search render for `query` whose fetch is held open until the
   * caller invokes `release()`. All other requests resolve immediately.
   */
  function stubHeldSearch(heldQuery: string): { release: () => void } {
    let release!: () => void;
    const held = new Promise<Response>((resolve) => {
      release = () =>
        resolve(
          mockResponse({
            body: {
              query: heldQuery,
              path: '',
              results: [
                fileEntry({
                  name: 'result-for-' + heldQuery,
                  path: joinPathHelper('docs', 'result-for-' + heldQuery),
                }),
              ],
            } as SearchResult,
          }),
        );
    });

    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        if (query === heldQuery) {
          return held;
        }
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      return mockResponse({ status: 200, body: {} });
    });

    return { release };
  }

  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('does NOT show a spinner when a search resolves within 500ms (fast search)', async () => {
    // A search that comes back quickly must never flash the loading spinner:
    // the 500ms spinner timer is cleared before it ever fires.
    const { results } = setup({ hash: toSearchHash('fast-query', '') });

    // Advance to just under the 500ms threshold: the fast search resolves
    // (microtask) and clears the spinner timer before it can fire.
    await vi.advanceTimersByTimeAsync(499);
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-fast-query');

    // Well past 500ms — the timer was already cleared, so still no spinner.
    await vi.advanceTimersByTimeAsync(501);
    expect(results.querySelector('.search-spinner')).toBeNull();
  });

  it('shows a spinner after 500ms while a search fetch is still in flight', async () => {
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });

    // Before the 500ms threshold: the held search is in flight but no spinner yet.
    await vi.advanceTimersByTimeAsync(499);
    expect(results.querySelector('.search-spinner')).toBeNull();

    // At 500ms the search is still held, so the spinner appears.
    await vi.advanceTimersByTimeAsync(1);
    const spinner = results.querySelector('.search-spinner');
    expect(
      spinner,
      'a .search-spinner element must appear after 500ms of an in-flight search',
    ).toBeTruthy();
    const spinningIcon = spinner!.querySelector('.bi-arrow-repeat.spinning');
    expect(spinningIcon, 'the spinner must contain a .bi-arrow-repeat.spinning icon').toBeTruthy();

    // Release the held fetch — results render and the spinner is removed.
    release();
    await vi.advanceTimersByTimeAsync(0);
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-slow-query');
  });

  it('does NOT show a spinner during browse fetches', async () => {
    const { results } = setup({ hash: toBrowseHash('docs') });
    await vi.advanceTimersByTimeAsync(1000);
    expect(results.querySelector('.search-spinner')).toBeNull();
  });

  it('removes the spinner when a search fetch fails (error message replaces it)', async () => {
    fetchMock.mockImplementation(async () => mockResponse({ status: 500, text: 'boom' }));
    const { results } = setup({ hash: toSearchHash('fail-query', '') });

    // The failing search resolves quickly (< 500ms), so no spinner shows; the
    // error handler replaces the results content regardless.
    await vi.advanceTimersByTimeAsync(1000);
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.textContent).toContain('Error');
  });

  it('a superseded search render does not leave a stale spinner', async () => {
    const { release } = stubHeldSearch('slow');
    const { results } = setup();
    await vi.advanceTimersByTimeAsync(1000); // settle the initial browse render

    // Start a held search and let its spinner appear, then navigate away.
    navigate(toSearchHash('slow', ''));
    await vi.advanceTimersByTimeAsync(500);
    expect(results.querySelector('.search-spinner')).toBeTruthy();

    navigate(toBrowseHash('elsewhere'));
    await vi.advanceTimersByTimeAsync(0); // browse resolves and clears the results

    // The browse render cleared the results; no spinner should remain.
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();

    // The slow search finally resolves — must not re-add a spinner or clobber.
    release();
    await vi.advanceTimersByTimeAsync(0);

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.textContent).toContain('child-of-elsewhere');
  });
});

/**
 * Shared test helpers for the `src/app/*.test.ts` per-domain test files.
 *
 * Extracted verbatim from the former `src/app.test.ts` monolith (split per
 * task-29) so each focused test file can import only what it needs. Houses:
 *
 *   - fixture builders: `fileEntry`, `browseResult`, `joinPathHelper`,
 *     `browseRoute`, `searchRoute`
 *   - timing: `flush`
 *   - DOM scaffolding: `setup`, `setupCleared`, `SetupCtx`
 *   - table/row traversal: `dataRows`, `rowByName`, `cellsOf`,
 *     `clickNameLink`, `buttonsByText`
 *   - the shared per-test fetch stub lifecycle: `installAppTestLifecycle` plus
 *     the `fetchMock` live binding it rebinds each test
 *
 * `browseRoute` / `searchRoute` construct `Route` fixtures. They were
 * referenced by the dead-CSS characterization suite in the monolith but never
 * defined (a latent bug that left those tests throwing `ReferenceError`); they
 * are defined here so those scenarios finally run. `renderBrowse` /
 * `renderSearch` no longer take a `route` argument (its removal is pinned by
 * the route-independence suite), so the value is ignored at runtime — but it
 * must be a defined expression rather than a bare `ReferenceError`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/app/test-helpers.ts` entry in `tsconfig.json`'s `exclude` array
 * (mirroring the `src/test-utils/**` glob added by task-27), so it is never
 * shipped to `wwwroot/dist`. Only test files import it.
 */
import { vi, beforeEach, afterEach } from 'vitest';
import { startApp } from '../app';
import type { BrowseResult, FileEntry, SearchResult } from '../api';
import type { Route } from '../router';
import { mockResponse } from '../test-utils/mock-response';

/* ===========================================================================
 * Constants & fixture builders
 * ========================================================================= */

export const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
export const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

export function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
    itemCount: opts.itemCount ?? 0,
  };
}

export function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
export function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

/** Build a browse `Route` fixture. */
export function browseRoute(path: string): Route {
  return { view: 'browse', path, query: '' };
}

/** Build a search `Route` fixture. */
export function searchRoute(query: string, path: string = ''): Route {
  return { view: 'search', query, path };
}

/* ===========================================================================
 * Timing
 * ========================================================================= */

/** Let pending microtasks / queued hashchange renders settle. */
export const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

/* ===========================================================================
 * DOM scaffolding
 * ========================================================================= */

export interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchWrapper: HTMLElement;
  searchClearBtn: HTMLButtonElement;
  searchIcon: HTMLElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
export function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchWrapper: root.querySelector('.search-wrapper') as HTMLElement,
    searchClearBtn: root.querySelector('.search-wrapper .clear-btn') as HTMLButtonElement,
    searchIcon: root.querySelector('.search-wrapper .search-icon') as HTMLElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
export async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* ===========================================================================
 * Table-traversal helpers (browser-agnostic; work on Element).
 * ========================================================================= */

export function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
export function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find((tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name);
}
export function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
export function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
export function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Shared per-test fetch stub lifecycle
 *
 * `fetchMock` is an `export let` live binding: `installAppTestLifecycle()`'s
 * `beforeEach` rebinds it to a fresh permissive `vi.fn` each test, and every
 * importer sees the rebound value (ESM live bindings — verified against this
 * vitest setup). Tests therefore read `fetchMock.mock.calls` exactly as the
 * monolith did, with no per-file `let fetchMock` declaration.
 * ========================================================================= */

export let fetchMock: ReturnType<typeof vi.fn> = vi.fn(async () => mockResponse({ body: {} }));

/**
 * Register the shared `beforeEach` (permissive default fetch stub) and
 * `afterEach` (DOM + mock cleanup) used by every split app test file. Call
 * exactly once at module top level in each `*.test.ts`.
 */
export function installAppTestLifecycle(): void {
  beforeEach(() => {
    // A permissive default: every browse/search GET returns a recognizable
    // result derived from the requested path/query, and every mutation returns
    // 200. Individual tests override with `fetchMock.mockImplementation(...)`
    // or `.mockResolvedValueOnce(...)` for specific scenarios. This also means
    // incidental background renders (e.g. from accumulated hashchange
    // listeners) never throw unhandled rejections.
    fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
    // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
    // the previous mount's render() listener on re-mount (so listeners no longer
    // accumulate across tests), but the CURRENT test's listener remains active
    // until the next test's setup() re-mounts. Resetting the hash after
    // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
    // fetch. We clear the body first (while fetch is still stubbed, so any
    // in-flight render's already-issued request stays mocked) and reset the hash
    // at the start of the next test's setup() instead.
    document.body.innerHTML = '';
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });
}

/**
 * Tests for `src/app.ts`'s module surface and `startApp` bootstrap: the
 * imperative DOM scaffold it builds, the dialog open/close + shared-widget
 * move wiring, and the two characterization suites that pin app.ts's retained
 * imports and its (dead-)CSS-selector-relevant DOM output.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). The shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded by these suites (carried over from the monolith):
 *  - The action controls Delete / Move / Copy are `<button>` elements whose
 *    trimmed `textContent` is exactly `"Delete"` / `"Move"` / `"Copy"`.
 *  - Importing `./app` must not side-effect when there is no `#app` element.
 */
import { describe, it, expect, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from '../app';
import { toBrowseHash, toSearchHash } from '../router';
import {
  setup,
  setupCleared,
  browseResult,
  fileEntry,
  cellsOf,
  rowByName,
  clickNameLink,
  dataRows,
  browseRoute,
  searchRoute,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * Module surface / bootstrap guard
 * ========================================================================= */
describe('app module surface', () => {
  it('exports startApp, renderBrowse, and renderSearch as functions', () => {
    expect(typeof startApp).toBe('function');
    expect(typeof renderBrowse).toBe('function');
    expect(typeof renderSearch).toBe('function');
  });

  it('can be imported without a DOM #app element present (bootstrap is guarded)', () => {
    // Importing this test file already imported '../app'. That import ran the
    // bootstrap line `const root = document.getElementById('app'); if (root)
    // startApp(root);` against an empty document and did not throw — reaching
    // this assertion proves the guard. We additionally assert there is no
    // stray dialog created at module load time.
    expect(document.querySelector('dialog.browser-dialog')).toBeNull();
  });
});

/* ===========================================================================
 * startApp — DOM structure & dialog wiring
 * ========================================================================= */
describe('startApp', () => {
  describe('DOM structure', () => {
    it('creates a trigger button labelled "Browse Files"', () => {
      const { trigger } = setup();
      expect(trigger).toBeTruthy();
      expect(trigger.className).toBe('trigger');
      expect(trigger.textContent?.trim()).toBe('Browse Files');
    });

    it('creates a native <dialog class="browser-dialog"> that starts closed', () => {
      const { dialog } = setup();
      expect(dialog).toBeTruthy();
      expect(dialog.tagName).toBe('DIALOG');
      expect(dialog.className).toBe('browser-dialog');
      expect(dialog.open).toBe(false);
    });

    it('renders a header with a centered title span and an icon Close button', () => {
      const { dialog, closeBtn } = setup();
      expect(closeBtn).toBeTruthy();
      expect(closeBtn.className).toBe('close-btn');
      // No visible text — it's an icon button, so it carries an aria-label.
      expect(closeBtn.textContent?.trim()).toBe('');
      expect(closeBtn.getAttribute('aria-label')).toBe('Close');
      const icon = closeBtn.querySelector('.bi');
      expect(icon).toBeTruthy();
      expect(icon?.className).toContain('bi-x-lg');
      expect(dialog.contains(closeBtn)).toBe(true);
      const titleSpan = dialog.querySelector('.title');
      expect(titleSpan).toBeTruthy();
      expect(titleSpan?.textContent).toBe('File Browser');
    });

    it('renders a toolbar with a breadcrumb container', () => {
      const { breadcrumb } = setup();
      expect(breadcrumb).toBeTruthy();
      expect(breadcrumb.className).toBe('breadcrumb');
    });

    it('renders a search text input inside a .search-wrapper with a magnifying glass icon and a clear button', () => {
      const { searchInput, searchWrapper, searchIcon, searchClearBtn } = setup();
      expect(searchInput).toBeTruthy();
      expect(searchInput.type).toBe('text');
      expect(searchInput.getAttribute('placeholder')).toBe('Search...');
      // The wrapper contains the input, search icon, and clear button
      expect(searchWrapper).toBeTruthy();
      expect(searchWrapper.className).toBe('search-wrapper');
      expect(searchWrapper.contains(searchInput)).toBe(true);
      // Magnifying glass icon at idle
      expect(searchIcon).toBeTruthy();
      expect(searchIcon.className).toContain('bi-search');
      expect(searchIcon.className).toContain('search-icon');
      expect(searchWrapper.contains(searchIcon)).toBe(true);
      // Clear (X) button
      expect(searchClearBtn).toBeTruthy();
      expect(searchClearBtn.className).toBe('clear-btn');
      expect(searchClearBtn.getAttribute('aria-label')).toBe('Clear search');
      const clearIcon = searchClearBtn.querySelector('.bi');
      expect(clearIcon).toBeTruthy();
      expect(clearIcon?.className).toContain('bi-x-lg');
      expect(searchWrapper.contains(searchClearBtn)).toBe(true);
    });

    it('does NOT render a Search button (removed in favor of instant debounced search)', () => {
      const { root } = setup();
      const buttons = Array.from(root.querySelectorAll('button'));
      const searchButtons = buttons.filter((b) => (b.textContent ?? '').trim() === 'Search');
      expect(searchButtons).toHaveLength(0);
    });

    it('renders an empty .results container and a .status footer', () => {
      const { results, status } = setup();
      expect(results).toBeTruthy();
      expect(results.className).toBe('results');
      expect(status).toBeTruthy();
      expect(status.tagName).toBe('FOOTER');
      expect(status.className).toBe('status');
    });
  });

  describe('dialog open/close wiring', () => {
    it('opens the dialog (showModal) when the trigger is clicked', () => {
      const { dialog, trigger } = setup();
      const showSpy = vi.spyOn(dialog, 'showModal');

      trigger.click();

      expect(showSpy).toHaveBeenCalledTimes(1);
      expect(dialog.open).toBe(true);
    });

    it('closes the dialog when the Close button is clicked', () => {
      const { dialog, closeBtn } = setup();
      dialog.showModal();
      expect(dialog.open).toBe(true);
      const closeSpy = vi.spyOn(dialog, 'close');

      closeBtn.click();

      expect(closeSpy).toHaveBeenCalledTimes(1);
      expect(dialog.open).toBe(false);
    });
  });

  /* The file browser is a single chromeless widget shared between the embedded
     host (primary view) and the dialog body. Opening the dialog MOVES the same
     nodes into the dialog; closing moves them back — so there is never a second
     copy, and the embedded view stays chromeless (no frame/title). */
  describe('shared widget (embedded host vs dialog)', () => {
    it('renders an embedded host and a single chromeless .file-browser widget', () => {
      const { embeddedHost, widget } = setup();
      expect(embeddedHost).toBeTruthy();
      expect(embeddedHost.className).toBe('file-browser-host');
      expect(widget).toBeTruthy();
      expect(widget.className).toBe('file-browser');
      // There is exactly one widget in the whole document.
      expect(document.querySelectorAll('.file-browser')).toHaveLength(1);
    });

    it('hosts the widget in the embedded host while the dialog is closed', () => {
      const { embeddedHost, widget, dialog } = setup();
      expect(embeddedHost.contains(widget)).toBe(true);
      // The widget (and thus its table/search/status) is NOT inside the dialog
      // until the dialog is opened.
      expect(dialog.contains(widget)).toBe(false);
    });

    it('moves the widget into the dialog body when the dialog opens', () => {
      const { embeddedHost, widget, dialog, trigger } = setup();

      trigger.click();

      expect(dialog.open).toBe(true);
      expect(dialog.contains(widget)).toBe(true);
      // Same node reference, not a clone — only one widget exists.
      expect(document.querySelectorAll('.file-browser')).toHaveLength(1);
      expect(embeddedHost.contains(widget)).toBe(false);
    });

    it('moves the widget back to the embedded host when the dialog closes', () => {
      const { embeddedHost, widget, dialog, trigger } = setup();
      trigger.click();
      expect(dialog.contains(widget)).toBe(true);

      dialog.close();

      expect(dialog.open).toBe(false);
      expect(embeddedHost.contains(widget)).toBe(true);
      expect(dialog.contains(widget)).toBe(false);
    });

    it('the embedded widget carries no dialog chrome (no title/close-btn)', () => {
      const { widget } = setup();
      // The titlebar (title + close button) is dialog-only chrome; the embedded
      // widget must not contain a title or close button.
      expect(widget.querySelector('.title')).toBeNull();
      expect(widget.querySelector('.close-btn')).toBeNull();
      expect(widget.querySelector('.dialog-header')).toBeNull();
    });
  });
});

/* ===========================================================================
 * Import characterization (safety net for unused-import removal)
 *
 * `src/app.ts` imports `parseHash` (from ./router.js), `parentPath`, and
 * `basename` (from ./format.js) that are never referenced in the module body
 * and are slated for removal. Removing unused imports cannot change runtime
 * behavior, so these tests guard the OTHER behaviors: they pin the observable
 * outputs that depend on the imports which STAY — especially the ones that
 * share an import line with the removed names, where a careless edit could
 * drop a needed sibling. Each assertion checks a concrete value tied to one
 * retained import's real usage in the app; if that import were removed, the
 * referenced call would throw (ReferenceError) or emit wrong output and the
 * test would fail.
 *
 * Retained imports exercised here:
 *   format.js: joinPath, normalizeRelativePath, formatBytes, formatDate
 *   router.js: toBrowseHash, toSearchHash
 * (getCurrentRoute / subscribe / navigate are already covered by the render
 * orchestration and toolbar-handler suites.)
 * ========================================================================= */
describe('import characterization (KEEP-list behaviors)', () => {
  // Local leaf finder; the breadcrumb describe has its own scoped copy.
  function leafByText(container: Element, text: string): HTMLElement | undefined {
    return Array.from(container.querySelectorAll('*')).find(
      (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
    ) as HTMLElement | undefined;
  }

  /* --- format.js KEEP imports (siblings of the removed parentPath/basename) --- */

  describe('joinPath (breadcrumb cumulative paths)', () => {
    it('joins each cumulative segment across three path levels', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }));

      leafByText(breadcrumb, 'c')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b/c'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('normalizeRelativePath (breadcrumb path cleaning)', () => {
    it('collapses leading/doubled/trailing slashes before splitting segments', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '//a//b//' }));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('formatBytes (size column)', () => {
    it('renders a 0-byte file as "0 B" (sub-KB integer branch)', async () => {
      const entry = fileEntry({ name: 'empty.txt', path: 'docs/empty.txt', size: 0 });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const sizeCell = cellsOf(rowByName(results.querySelector('table')!, 'empty.txt')!)[1];
      expect(sizeCell.textContent?.trim()).toBe('0 B');
    });
  });

  describe('formatDate (modified column)', () => {
    it('renders an empty Modified cell when lastModified is empty (fallback)', async () => {
      const entry = fileEntry({ name: 'nodate.txt', path: 'docs/nodate.txt', lastModified: '' });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const modifiedCell = cellsOf(rowByName(results.querySelector('table')!, 'nodate.txt')!)[2];
      expect(modifiedCell.textContent).toBe('');
    });
  });

  /* --- router.js KEEP imports (siblings of the removed parseHash) --- */

  describe('toBrowseHash (per-segment percent-encoding)', () => {
    it('encodes spaces in directory names when navigating into a folder', async () => {
      const dir = fileEntry({ name: 'my folder', path: 'docs/my folder', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      clickNameLink(rowByName(results.querySelector('table')!, 'my folder')!);

      expect(window.location.hash).toBe('#/browse/docs/' + encodeURIComponent('my folder'));
      expect(window.location.hash).toBe(toBrowseHash('docs/my folder'));
    });
  });

  describe('toSearchHash (query/path percent-encoding)', () => {
    it('encodes special characters in the search query and scope path', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000); // settle initial render

        searchInput.value = 'a & b=c?';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200); // fire the debounce

        const expected =
          '#/search?q=' + encodeURIComponent('a & b=c?') + '&path=' + encodeURIComponent('docs');
        expect(window.location.hash).toBe(expected);
        expect(window.location.hash).toBe(toSearchHash('a & b=c?', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });
  });
});

/* ===========================================================================
 * Dead CSS selector characterization
 *
 * `src/app.css` ships rule blocks whose selectors are NEVER emitted by app.ts,
 * so they have ZERO observable effect on the rendered UI. They are slated for
 * deletion in a dead-code cleanup. The tests below pin the JS-side invariants
 * that make that deletion provably safe:
 *
 *   - the rendered DOM must never produce an element the removed selectors
 *     could match; and
 *   - any behavior the dead rules *appear* to supply must actually be provided
 *     by an independent mechanism that survives the deletion.
 *
 * Removed selectors under test:
 *   (1) `.breadcrumb .separator`         — breadcrumb separators are class-less
 *       `<span>`s holding the literal "/"; nothing carries `separator`.
 *   (2) `.toolbar label.upload-btn` (+ its `:hover` + the descendant
 *       `input[type=file]` rule) — historically dead because the upload label
 *       used `btn`, never `upload-btn`. The toolbar upload control has since
 *       been removed entirely (upload is now reached via the folder/directory
 *       context menus), so these selectors match even less; the suite below
 *       pins only the still-relevant breadcrumb invariant.
 *
 * (`.folder-row` was formerly in this dead list, but it is now a LIVE class:
 * folder rows and the ".." parent row carry `folder-row` / `parent-row` so the
 * whole row is click-to-browse — see the dedicated suite below.)
 *
 * These assertions pass against the current (pre-cleanup) code AND must keep
 * passing after the dead rules are deleted, because they depend only on the
 * DOM app.ts emits — which the cleanup does not touch. (The environment does
 * not load app.css, so a missing rule cannot change `getComputedStyle` here;
 * these tests instead prove the rule could never have matched anything.)
 *
 * NOTE: these tests pass a `Route` fixture (`browseRoute` / `searchRoute`) as
 * a second argument to `renderBrowse` / `renderSearch`. That argument is a
 * leftover from before the route parameter was removed (see the
 * route-independence suite in `render-orchestration.test.ts`) and is silently
 * ignored at runtime; it is preserved verbatim so the scenario is unchanged.
 * ========================================================================= */
describe('dead CSS selector characterization', () => {
  describe('breadcrumb separators are class-less spans (no `.separator`)', () => {
    /** Leaf <span>s whose visible text is exactly the breadcrumb slash. */
    function slashSeparators(container: Element): HTMLSpanElement[] {
      return Array.from(container.querySelectorAll('span')).filter(
        (s) => (s.textContent ?? '').trim() === '/',
      ) as HTMLSpanElement[];
    }

    it('renders one "/" separator per path segment, each a class-less <span>', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }), browseRoute('a/b/c'));

      const separators = slashSeparators(breadcrumb);
      // a/b/c → 3 segments → 3 separators (Home / a / b / c). Verifying the
      // count also pins that the separators are still visibly rendered.
      expect(separators).toHaveLength(3);
      for (const sep of separators) {
        expect(sep.tagName).toBe('SPAN');
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      // The dead selector `.breadcrumb .separator` matches nothing.
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('renders no separators for the root path, and still no `.separator` anywhere', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '', entries: [] }), browseRoute(''));

      expect(slashSeparators(breadcrumb)).toHaveLength(0);
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('search-scope breadcrumbs also use class-less "/" separators', async () => {
      const { breadcrumb } = await setupCleared();
      renderSearch({ query: 'q', path: 'x/y', results: [] }, searchRoute('q', 'x/y'));

      const separators = slashSeparators(breadcrumb);
      expect(separators).toHaveLength(2);
      for (const sep of separators) {
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });
  });
});

/* ===========================================================================
 * Click-to-browse rows — whole-row navigation
 *
 * Folder rows and the ".." parent row browse into their target on a click
 * ANYWHERE in the row (not only on the name link), so a user is not forced to
 * hit the narrow link. Clicks in a folder row's actions cell (the ⋮ button +
 * its menu) are excluded so those controls keep working. File rows do nothing
 * on left-click. The row classes `folder-row` / `parent-row` drive the pointer
 * cursor (see app.css).
 * ========================================================================= */
describe('click-to-browse rows', () => {
  it('folder rows carry `folder-row`, the ".." parent row carries `parent-row`, and file rows carry neither', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [dir, file] }));

    const rows = dataRows(results.querySelector('table')!);
    expect(rows).toHaveLength(3); // parent + folder + file
    const [parentRow, folderRow, fileRow] = rows;
    expect(parentRow.classList.contains('parent-row')).toBe(true);
    expect(folderRow.classList.contains('folder-row')).toBe(true);
    expect(fileRow.classList.contains('folder-row')).toBe(false);
    expect(fileRow.classList.contains('parent-row')).toBe(false);
    // Exactly the two navigable rows carry a click-to-browse class.
    expect(document.querySelectorAll('.folder-row, .parent-row')).toHaveLength(2);
  });

  it('clicking the Size cell of a folder row navigates into the folder', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

    const folderRow = rowByName(results.querySelector('table')!, 'sub')!;
    cellsOf(folderRow)[1].click(); // Size cell (item count) — not the name link

    expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
  });

  it('clicking the Modified cell of a folder row navigates into the folder', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

    const folderRow = rowByName(results.querySelector('table')!, 'sub')!;
    cellsOf(folderRow)[2].click(); // Modified cell

    expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
  });

  it('clicking the ".." parent row (not its link) navigates to the parent path', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [] }));

    const parentRow = rowByName(results.querySelector('table')!, '..')!;
    cellsOf(parentRow)[2].click(); // Modified cell — not the ".." link

    expect(window.location.hash).toBe(toBrowseHash('docs'));
  });

  it('clicking a file row does NOT navigate', async () => {
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));
    window.location.hash = '';

    rowByName(results.querySelector('table')!, 'a.txt')!.click();

    expect(window.location.hash).toBe('');
  });

  it('clicking the ⋮ button (in the actions cell) opens the menu and does NOT navigate', async () => {
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [dir] }));
    window.location.hash = '';

    const folderRow = rowByName(results.querySelector('table')!, 'sub')!;
    const btn = cellsOf(folderRow)[3].querySelector('.row-menu-btn') as HTMLButtonElement;
    const menu = cellsOf(folderRow)[3].querySelector('.row-menu') as HTMLElement;
    btn.click();

    expect(menu.hidden).toBe(false); // menu opened
    expect(window.location.hash).toBe(''); // no navigation from the actions cell
  });
});

/**
 * Shared services for the file-browser app modules.
 *
 * The file-browser is split across several focused modules (dom-builders,
 * render-browse, render-search, toolbar-handlers, render-orchestrator). They
 * all need access to three cross-cutting things that `startApp` establishes
 * once per mount:
 *
 *   - the {@link ApiClient} singleton (used for fetches and download URLs);
 *   - the DOM element refs the render helpers write into (results, status,
 *     breadcrumb, search input);
 *   - a "render hook" that action-button handlers and the upload handler call
 *     to trigger a fresh route dispatch (used instead of importing the
 *     orchestrator directly, which would create a module cycle: orchestrator →
 *     render-browse → dom-builders → orchestrator).
 *
 * Centralizing them here keeps the cross-module dependency graph acyclic and
 * makes the re-bind-on-remount contract explicit — replacing the bare
 * module-level `let resultsEl!: HTMLElement` variables that used to live in
 * `app.ts`. `render-orchestrator.init` re-binds the refs every mount, so the
 * render helpers always target the most recently mounted app.
 */
import { ApiClient } from '../api.js';

/** The DOM element refs established by each `startApp` mount. */
export interface DomRefs {
  results: HTMLElement;
  status: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
}

/* -------------------------------------------------------------------------
 * API singleton
 *
 * Created once at module load, exactly as the original `app.ts` created
 * `const api = new ApiClient();` at its top level. The constructor performs
 * no I/O, so creating it before `fetch` is stubbed in a test is safe.
 * ---------------------------------------------------------------------- */
const api = new ApiClient();

/** The shared API client (used for fetches and download-URL construction). */
export function getApi(): ApiClient {
  return api;
}

/* -------------------------------------------------------------------------
 * DOM refs — rebound by `render-orchestrator.init` on every `startApp` mount
 * so `renderBrowse` / `renderSearch` always target the most recent mount.
 *
 * The definite-assignment assertions mirror the original `let resultsEl!:
 * HTMLElement` pattern: the refs are uninitialized only until the first
 * `init()` call, which always runs before any render helper reads them.
 * ---------------------------------------------------------------------- */
let results!: HTMLElement;
let status!: HTMLElement;
let breadcrumb!: HTMLElement;
let searchInput!: HTMLInputElement;

/** Bind the DOM refs for the current mount. Called from the orchestrator's `init`. */
export function setRefs(refs: DomRefs): void {
  results = refs.results;
  status = refs.status;
  breadcrumb = refs.breadcrumb;
  searchInput = refs.searchInput;
}

export function getResults(): HTMLElement {
  return results;
}

export function getStatus(): HTMLElement {
  return status;
}

export function getBreadcrumb(): HTMLElement {
  return breadcrumb;
}

export function getSearchInput(): HTMLInputElement {
  return searchInput;
}

/* -------------------------------------------------------------------------
 * Render hook
 *
 * Action-button handlers (in dom-builders) and the upload handler (in
 * toolbar-handlers) call `rerender()` to trigger a fresh route dispatch. They
 * cannot import `render` from render-orchestrator.ts directly without creating
 * the cycle noted above, so the orchestrator registers its `render` function
 * here during `init` and the callers invoke it indirectly through `rerender`.
 * ---------------------------------------------------------------------- */
let renderHook: () => Promise<void> = async () => {};

/** Register the route-dispatching render function. */
export function setRenderHook(fn: () => Promise<void>): void {
  renderHook = fn;
}

/** Trigger a fresh render via the registered hook. No-op until `setRenderHook` is called. */
export function rerender(): Promise<void> {
  return renderHook();
}

/**
 * Route dispatcher and rendering-lifecycle owner.
 *
 * `render` reads the current route, fetches the matching result from the API,
 * and delegates to `renderBrowse` / `renderSearch`. It guards against render
 * races (a slower, superseded fetch cannot clobber fresher results) via a
 * monotonic token checked after each `await`.
 *
 * `init` is called once per `startApp` mount: it binds the freshly-built DOM
 * refs into the shared context, registers `render` as the re-render hook (so
 * action buttons and uploads can trigger it without a circular import), tears
 * down any previous mount's hashchange listener, subscribes a new one, and
 * kicks off the initial render.
 */
import { getCurrentRoute, subscribe } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getResults, setRefs, setRenderHook, type DomRefs } from './context.js';
import { renderBrowse } from './render-browse.js';
import { renderSearch } from './render-search.js';

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `init` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/**
 * Bind the freshly-built DOM refs into the shared context, register `render`
 * as the re-render hook, tear down any previous mount's hashchange listener,
 * subscribe a new one, and kick off the initial render.
 */
export function init(refs: DomRefs): void {
  setRefs(refs);
  setRenderHook(render);
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/**
 * Route dispatcher.
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 */
export async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  // Debounced spinner: a search fetch only shows a spinner if it is still in
  // flight after 500ms, so fast searches never flash a loading indicator. The
  // timer is cleared on every exit path (success, error, superseded), and its
  // callback also bails if a newer render has claimed the slot — so a slower,
  // superseded fetch can never re-add a stale spinner. For browse routes, no
  // spinner is ever shown. When results do render, the spinner (if shown) is
  // removed naturally: `renderSearch(result)` clears the container before
  // building the table, and the error handler's `textContent` replaces all.
  let spinnerTimer: ReturnType<typeof setTimeout> | null = null;
  const clearSpinnerTimer = (): void => {
    if (spinnerTimer !== null) {
      clearTimeout(spinnerTimer);
      spinnerTimer = null;
    }
  };
  if (route.view === 'search') {
    spinnerTimer = setTimeout(() => {
      spinnerTimer = null;
      // A newer render owns the slot — don't re-add a stale spinner.
      if (myToken !== renderToken) return;
      const spinnerWrap = document.createElement('div');
      spinnerWrap.className = 'search-spinner';
      const spinnerIcon = document.createElement('i');
      spinnerIcon.className = 'bi bi-arrow-repeat spinning';
      spinnerWrap.appendChild(spinnerIcon);
      resultsEl.appendChild(spinnerWrap);
    }, 500);
  }
  try {
    if (route.view === 'browse') {
      const result = await getApi().browse(normalizeRelativePath(route.path));
      clearSpinnerTimer();
      if (myToken !== renderToken) return;
      renderBrowse(result);
    } else {
      const result = await getApi().search(route.query, normalizeRelativePath(route.path));
      clearSpinnerTimer();
      if (myToken !== renderToken) return;
      renderSearch(result);
    }
  } catch (err) {
    clearSpinnerTimer();
    // A superseded render must not even commit its error.
    if (myToken !== renderToken) return;
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent =
      err instanceof Error ? 'Error: ' + err.message : 'Error: ' + String(err);
  }
}

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload-into-folder handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + .search-wrapper (search <input> +
 *                search-icon + clear-btn)
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, clearSearch } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  // Search affordance: a wrapper holding the input, a leading search icon,
  // and a trailing clear button (the latter toggled purely by CSS via
  // `:placeholder-shown`, so it needs no ref in DomRefs).
  const searchWrapper = document.createElement('div');
  searchWrapper.className = 'search-wrapper';
  const searchIcon = document.createElement('i');
  searchIcon.className = 'bi bi-search search-icon';
  const searchClearBtn = document.createElement('button');
  searchClearBtn.className = 'clear-btn';
  searchClearBtn.type = 'button';
  searchClearBtn.setAttribute('aria-label', 'Clear search');
  const clearIcon = document.createElement('i');
  clearIcon.className = 'bi bi-x-lg';
  searchClearBtn.append(clearIcon);
  // ORDER MATTERS: input first, then icon, then clear-btn (CSS uses ~ sibling combinator)
  searchWrapper.append(searchInput, searchIcon, searchClearBtn);
  toolbar.append(breadcrumbEl, searchWrapper);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  // Debounced search: re-fire `doSearch` 200ms after the last keystroke so
  // typing a query doesn't pound the API on every character.
  let searchDebounceTimer: ReturnType<typeof setTimeout> | null = null;
  searchInput.addEventListener('input', () => {
    if (searchDebounceTimer !== null) {
      clearTimeout(searchDebounceTimer);
    }
    searchDebounceTimer = setTimeout(() => {
      searchDebounceTimer = null;
      doSearch();
    }, 200);
  });
  // Clear button: wipe the input and return to the browse view.
  searchClearBtn.addEventListener('click', clearSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    } else if (event.key === 'Escape') {
      // stopPropagation is critical: when the widget lives inside the open
      // <dialog>, the native ESC-to-close would otherwise dismiss the dialog.
      event.stopPropagation();
      clearSearch();
    }
  });

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

